// Send to all peers
for (peer of peers) {
  POST https://{peer.endpoint}/sync/announce
  { ...announcement }
}
```

### 4.2 Receive Announcements
```javascript
app.post('/sync/announce', async (req, res) => {
  const announcement = req.body;

  // Verify signature
  if (!verifySignature(announcement, announcement.signature, announcement.pubkey)) {
    res.status(400).json({ error: "Invalid signature" });
    return;
  }

  // Store in received_announcements table
  db.insert('received_announcements', announcement);

  res.json({ status: "received" });
});
```

### 4.3 Compare All Hashes
```javascript
// Wait for all announcements (or timeout)
await waitForAllAnnouncements(peers, timeout=60000);

// Collect all hashes
all_announcements = [
  my_announcement,
  ...received_announcements
];

// Group by hash
hash_groups = {};
for (ann of all_announcements) {
  if (!hash_groups[ann.state_hash]) {
    hash_groups[ann.state_hash] = [];
  }
  hash_groups[ann.state_hash].push(ann.node_id);
}

// Example result:
// {
//   "abc123...": ["A", "B"],  ← Majority
//   "xyz789...": ["C"]        ← Outlier
// }
```

### 4.4 Detect Majority
```javascript
quorum_size = Math.floor(peers.length / 2) + 1;  // 2 out of 3

majority_hash = null;
majority_nodes = [];

for (hash in hash_groups) {
  if (hash_groups[hash].length >= quorum_size) {
    majority_hash = hash;
    majority_nodes = hash_groups[hash];
    break;
  }
}

if (!majority_hash) {
  log.error("No majority detected - round failed");
  round_failed = true;
  return;
}
```

### 4.5 Identify Outliers
```javascript
all_nodes = all_announcements.map(a => a.node_id);
outlier_nodes = all_nodes.filter(n => !majority_nodes.includes(n));

// Example: outlier_nodes = ["C"]
```

