  const valid = verifySignature(bundle, bundle.signature, bundle.pubkey);
  if (!valid) {
    res.status(400).json({ error: "Invalid signature" });
    return;
  }

  // Store in received_bundles table
  db.insert('received_bundles', bundle);

  res.json({ status: "received" });
});
```

### 2.4 Wait for All Peers (or Timeout)
```javascript
timeout = setTimeout(() => {
  log.warn("Submit timeout - proceeding with received bundles");
  proceed_to_merge();
}, 30000);  // 30 seconds

// Check if all received
if (received_bundles.count >= peers.length - 1) {
  clearTimeout(timeout);
  proceed_to_merge();
}
```

### 2.5 Error Handling
```javascript
// Invalid signature
→ Reject bundle, log as malicious, exclude from merge

// Duplicate ledger (across bundles)
→ Keep first occurrence, discard duplicate

// Timeout (peer didn't submit)
→ Proceed without that peer's bundle
→ Log warning, mark peer as "slow"
```

### 2.6 Output
```
Received bundles from peers:
  - Bundle from A (my own)
  - Bundle from B ✅
  - Bundle from C ✅

Ready for Step 3: MERGE
```

---

┌─────────────────────────────────────────────────────────────────────────┐
│ STEP 3: MERGE (T+1:00 → T+1:30)                                        │
├─────────────────────────────────────────────────────────────────────────┤
│ Network: ❌ Local Processing (after receiving)                         │
│ Timeout: 30 seconds                                                     │
├─────────────────────────────────────────────────────────────────────────┤

## Detailed Flow

### 3.1 Collect All Bundles
```javascript
all_bundles = [
  my_bundle,
  ...received_bundles
];
```

### 3.2 Validate All Bundles
```javascript
for (bundle of all_bundles) {
  // Verify bundle signature
  if (!verifySignature(bundle, bundle.signature, bundle.pubkey)) {
    log.error("Invalid bundle signature", bundle.node_id);
    exclude_bundle(bundle);
    continue;
  }

  // Verify each ledger signature within bundle
  for (ledger of bundle.ledgers) {
    if (!verifySignature(ledger.data, ledger.signature, ledger.pubkey)) {
      log.error("Invalid ledger signature", ledger.id);
      remove_ledger(ledger);
    }
  }
}
```

### 3.3 Merge All Ledgers
```javascript
all_ledgers = [];
for (bundle of valid_bundles) {
  all_ledgers.push(...bundle.ledgers);
}
```

### 3.4 Remove Duplicates (by Ledger ID)
```javascript
seen_ids = new Set();
unique_ledgers = [];

for (ledger of all_ledgers) {
  if (!seen_ids.has(ledger.id)) {
    seen_ids.add(ledger.id);
    unique_ledgers.push(ledger);
  }
}
```

### 3.5 Sort by ULID (Deterministic)
```javascript
sorted_ledgers = unique_ledgers.sort((a, b) => {
  return a.id.localeCompare(b.id);  // ULID string comparison
});
```

### 3.6 Compute State Hash
```javascript
state_hash = sha256(JSON.stringify(sorted_ledgers));
// Example: "abc123def456..."
```

### 3.7 Output
```
Merged ledger set:
  - Total ledgers: 15
  - From A: 5 ledgers
  - From B: 3 ledgers
  - From C: 7 ledgers

State hash: "abc123..."

Ready for Step 4: COMPARE
```

---

┌─────────────────────────────────────────────────────────────────────────┐
│ STEP 4: COMPARE (T+1:30 → T+2:30)                                      │
├─────────────────────────────────────────────────────────────────────────┤
│ Network: ✅ Writer ↔ Writer (Broadcast)                                │
│ Timeout: 60 seconds                                                     │
├─────────────────────────────────────────────────────────────────────────┤

## Detailed Flow

### 4.1 Broadcast My Hash
```javascript
announcement = {
  node_id: my_node_id,
  round: round_number,
  state_hash: state_hash,  // "abc123..."
  timestamp: Date.now()
};

announcement.signature = sign(my_private_key, announcement);

// Send to all peers
for (peer of peers) {
  POST https://{peer.endpoint}/sync/announce
  { ...announcement }
}
```

### 4.2 Receive Announcements
```javascript
app.post('/sync/announce', async (req, res) => {
  const announcement = req.body;

  // Verify signature
  if (!verifySignature(announcement, announcement.signature, announcement.pubkey)) {
    res.status(400).json({ error: "Invalid signature" });
    return;
  }

  // Store in received_announcements table
  db.insert('received_announcements', announcement);

  res.json({ status: "received" });
});
```

### 4.3 Compare All Hashes
```javascript
// Wait for all announcements (or timeout)
await waitForAllAnnouncements(peers, timeout=60000);

// Collect all hashes
all_announcements = [
  my_announcement,
  ...received_announcements
];

// Group by hash
hash_groups = {};
for (ann of all_announcements) {
  if (!hash_groups[ann.state_hash]) {
    hash_groups[ann.state_hash] = [];
  }
  hash_groups[ann.state_hash].push(ann.node_id);
}

// Example result:
// {
//   "abc123...": ["A", "B"],  ← Majority
//   "xyz789...": ["C"]        ← Outlier
// }
```

### 4.4 Detect Majority
```javascript
quorum_size = Math.floor(peers.length / 2) + 1;  // 2 out of 3

majority_hash = null;
majority_nodes = [];

for (hash in hash_groups) {
  if (hash_groups[hash].length >= quorum_size) {
    majority_hash = hash;
    majority_nodes = hash_groups[hash];
    break;
  }
}

if (!majority_hash) {
  log.error("No majority detected - round failed");
  round_failed = true;
  return;
}
```

### 4.5 Identify Outliers
```javascript
all_nodes = all_announcements.map(a => a.node_id);
outlier_nodes = all_nodes.filter(n => !majority_nodes.includes(n));

// Example: outlier_nodes = ["C"]
```

### 4.6 Output
```
Consensus achieved:
  - Majority hash: "abc123..."
  - Majority nodes: ["A", "B"]
  - Outlier nodes: ["C"]

A and B proceed to SEAL
C is excluded (but ledgers preserved)

Ready for Step 5: SEAL
```

---

┌─────────────────────────────────────────────────────────────────────────┐
│ STEP 5: SEAL (T+2:30 → T+3:30)                                         │
├─────────────────────────────────────────────────────────────────────────┤
│ Network: ✅ Chain Signing (Majority Only)                              │
│ Timeout: 30 seconds per signer                                          │
├─────────────────────────────────────────────────────────────────────────┤

## Detailed Flow

### 5.1 Determine Signing Order
```javascript
// Sort by announcement arrival time (first to confirm signs first)
signing_order = majority_nodes.sort((a, b) => {
  ann_a = announcements.find(a => a.node_id === ann.node_id);
  ann_b = announcements.find(b => b.node_id === ann.node_id);
  return ann_a.timestamp - ann_b.timestamp;
});

// Ties broken by node_id ULID
// Example: ["A", "B"] (A arrived first)
```

### 5.2 First Signer (A)
```javascript
checkpoint_data = {
  round: round_number,
  state_hash: majority_hash,
  timestamp: Date.now(),
  signatures: []  // Empty for first signer
};

sig_A3 = sign(A_private_key, checkpoint_data);

checkpoint_data.signatures.push({
  node_id: "A",
  signature: sig_A3
});

// Pass to next signer (B)
POST https://B.endpoint/sync/seal
{ checkpoint_data }
```

### 5.3 Second Signer (B)
```javascript
// Receive from A
checkpoint_data = req.body;

// Verify A's signature
if (!verifySignature(checkpoint_data, sig_A3, A_pubkey)) {
  throw new Error("Invalid signature from A");
}

// Add my signature
sig_B3 = sign(B_private_key, checkpoint_data);

checkpoint_data.signatures.push({
  node_id: "B",
  signature: sig_B3
});

// Check if we have enough signatures
if (checkpoint_data.signatures.length >= quorum_size) {
  // Checkpoint complete!
  checkpoint_complete = true;

  // Notify all signers
  for (signer of signing_order) {
    POST https://{signer.endpoint}/sync/complete
    { checkpoint_data }
  }
}
```

### 5.4 Timeout Handling
```javascript
// First signer timeout (30 sec)
if (!first_signature_received) {
  log.error("First signer timeout - round failed");
  round_failed = true;
  return;
}

// Second signer timeout (30 sec)
if (!second_signature_received) {
  log.error("Second signer timeout - round failed");
  round_failed = true;
  return;
}
```

### 5.5 Output
```
Checkpoint signed:
  - Round: 42
  - Hash: "abc123..."
  - Signatures: 
    - A: sig_A3 ✅
    - B: sig_B3 ✅

Quorum achieved (2 out of 3)

Ready for Step 6: CHECKPOINT
```

---

┌─────────────────────────────────────────────────────────────────────────┐
│ STEP 6: CHECKPOINT (T+3:30 → T+4:00)                                   │
├─────────────────────────────────────────────────────────────────────────┤
│ Network: ❌ Local Assembly                                              │
│ Timeout: 30 seconds                                                     │
├─────────────────────────────────────────────────────────────────────────┤

## Detailed Flow

### 6.1 Assemble Complete Checkpoint Object
```javascript
checkpoint = {
  round: round_number,
  state_hash: majority_hash,
  timestamp: checkpoint_timestamp,

  // All submissions (including outlier)
  submissions: [
    { node_id: "A", bundle_hash: "...", signature: "sig_A1" },
    { node_id: "B", bundle_hash: "...", signature: "sig_B1" },
    { node_id: "C", bundle_hash: "...", signature: "sig_C1" }
  ],

  // All confirmations (including outlier)
  confirmations: [
    { node_id: "A", state_hash: "abc", signature: "sig_A2" },
    { node_id: "B", state_hash: "abc", signature: "sig_B2" },
    { node_id: "C", state_hash: "xyz", signature: "sig_C2" }
  ],

  // Final signatures (majority only)
  signatures: [
    { node_id: "A", signature: "sig_A3" },
    { node_id: "B", signature: "sig_B3" }
  ],

  // Metadata
  excluded: ["C"],
  quorum_size: 2,
  total_writers: 3,
  status: "complete"
};
```

### 6.2 Verify Checkpoint Integrity
```javascript
// Verify all signatures
for (sig of checkpoint.signatures) {
  if (!verifySignature(checkpoint, sig.signature, sig.pubkey)) {
    throw new Error("Invalid checkpoint signature");
  }
}

// Verify state hash
computed_hash = sha256(JSON.stringify(sorted_ledgers));
if (computed_hash !== checkpoint.state_hash) {
  throw new Error("State hash mismatch");
}
```

### 6.3 Store Checkpoint
```sql
INSERT INTO checkpoints (
  round, state_hash, timestamp, 
  submissions, confirmations, signatures,
  excluded, status, created_at
) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?);
```

### 6.4 Update Ledger Status
```sql
UPDATE ledgers 
SET status = 'confirmed', 
    checkpoint_round = ? 
WHERE status = 'pending_submit';
```

### 6.5 Make Available for Phase 2
```javascript
// Checkpoint is now available at:
// GET /checkpoint/latest
// GET /checkpoint/round/:id

// Query nodes can pull (Phase 2: Propagation)
```

### 6.6 Output
```
✅ CONSENSUS PHASE COMPLETE

Checkpoint created:
  - Round: 42
  - Hash: "abc123..."
  - Signatures: 2 (A, B)
  - Status: complete

Next: Phase 2 (Propagation)
  - Query nodes will pull automatically
  - Writers wait for next round (5-minute mark)
```

---

┌─────────────────────────────────────────────────────────────────────────┐
│                    COMPLETE FLOW SUMMARY                                │
├─────────────────────────────────────────────────────────────────────────┤

## Timeline (5-Minute Round)

```
T+0:00 ─────────────────────────────────────────────► T+5:00
│
├─ STEP 1: COMMIT    (30 sec)  [T+0:00 → T+0:30]
│   Local prep, validate, bundle
│
├─ STEP 2: SUBMIT    (30 sec)  [T+0:30 → T+1:00]
│   Send to peers, receive from peers
│
├─ STEP 3: MERGE     (30 sec)  [T+1:00 → T+1:30]
│   Validate, combine, sort, hash
│
├─ STEP 4: COMPARE   (60 sec)  [T+1:30 → T+2:30]
│   Broadcast hash, detect majority
│
├─ STEP 5: SEAL      (60 sec)  [T+2:30 → T+3:30]
│   Chain signing (majority only)
│
├─ STEP 6: CHECKPOINT (30 sec) [T+3:30 → T+4:00]
│   Assemble, verify, store
│
└─ BUFFER          (60 sec)   [T+4:00 → T+5:00]
    Retry failed steps, wait for next round
```

## Questions Answered

| Question | Answer |
|----------|--------|
| **Writer discovery?** | L1 Node Registry (`GET /nodes?type=writer`) |
| **Clock sync?** | NTP required, ±10 second tolerance |
| **Round start?** | Timer-based (5-minute marks), no coordinator |
| **Ledger ordering?** | ULID sort (deterministic) |

---

┌─────────────────────────────────────────────────────────────────────────┐
│                    END OF CONSENSUS PROTOCOL SPEC                       │
└─────────────────────────────────────────────────────────────────────────┘

